import React, { useState, useRef, useEffect, forwardRef, useImperativeHandle } from 'react';
import type { MusicTrack, HeaderControls } from '../types.ts';
import FloatingPodcastButton from './FloatingPodcastButton.tsx';
import ListenerCounter from './ListenerCounter.tsx';

// Importaciones estáticas para evitar baches por carga asíncrona
import { ONLY_MUSIC, ONLY_PODCASTS, ONLY_JINGLES, ONLY_SEPARATORS } from '../data/music.ts';
import { GREETING_AUDIOS } from '../greetings.ts';
import { TIME_JINGLES } from '../data/timeJingles.ts';
import { NEWS_BROADCASTS } from '../data/broadcasts.ts';

const VIDEO_URLS: string[] = [
  'https://res.cloudinary.com/ddmj6zevz/video/upload/w_1280,q_auto:good/v1755907719/animaci%C3%B3n_APP_pvxjop.mp4',
  'https://res.cloudinary.com/ddmj6zevz/video/upload/w_1280,q_auto:good/v1756345297/14_okcuk0.mp4',
  'https://res.cloudinary.com/ddmj6zevz/video/upload/w_1280,q_auto:good/v1757874034/tu_compa%C3%B1%C3%ADa_247_srq9ah.mp4',
  'https://res.cloudinary.com/ddmj6zevz/video/upload/w_1280,q_auto:good/v1756612883/Vienen_las_Noticias_ujmv2i.mp4',
  'https://res.cloudinary.com/dnauavz56/video/upload/v1764950849/postales2_mdcweq.mp4',
  'https://res.cloudinary.com/dnauavz56/video/upload/v1764980525/atardecer_en_puerto_ikddmm.mp4'
];

const NICOLLE_AUDIO_URL = 'https://res.cloudinary.com/dgvkbrgre/video/upload/q_auto:good/v1756197263/exclusivo_del_nexo_nicolle_gxsl68.mp3';

interface HeaderProps {
  isPodcastModalOpen: boolean;
  onPodcastButtonClick: () => void;
  showPodcastButton: boolean;
  onLibraryButtonClick: () => void;
  isDarkMode: boolean;
  onToggleDarkMode: () => void;
}

const Header = forwardRef<HeaderControls, HeaderProps>((props, ref) => {
  const [isPlaying, setIsPlaying] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [currentTrack, setCurrentTrack] = useState<MusicTrack | null>(null);
  const [videoQueue, setVideoQueue] = useState<string[]>(() => [...VIDEO_URLS].sort(() => Math.random() - 0.5));
  const [trackCounter, setTrackCounter] = useState(0);

  const audioRef = useRef<HTMLAudioElement>(null);
  const videoRef = useRef<HTMLVideoElement>(null);

  const getNextRadioTrack = (): MusicTrack => {
    const hour = new Date().getHours();

    // 1. Prioridad: Noticias (Micro Temáticos)
    if (NEWS_BROADCASTS[hour] && currentTrack?.id !== NEWS_BROADCASTS[hour].id) {
      return NEWS_BROADCASTS[hour];
    }

    // 2. Cada 5 pistas: Saludos o Time Jingles
    if (trackCounter > 0 && trackCounter % 5 === 0) {
      const timeOfDay = hour < 12 ? 'morning' : hour < 19 ? 'afternoon' : 'night';
      const pool = Math.random() > 0.5 ? GREETING_AUDIOS[timeOfDay] : TIME_JINGLES[timeOfDay];
      const randomUrl = pool[Math.floor(Math.random() * pool.length)];
      return { id: `greet_${Date.now()}`, url: randomUrl, description: 'Sintonía El Nexo Digital' };
    }

    // 3. Cada 2 pistas: SEPARADORES (Prioridad Nicolle) o Jingles
    if (trackCounter > 0 && trackCounter % 2 === 0) {
      const isSeparator = Math.random() > 0.3; // 70% prob de ser separador
      if (isSeparator) {
        // 50% de probabilidad de que sea específicamente NICOLLE si toca un separador
        if (Math.random() < 0.5 && currentTrack?.id !== 'nicolle_id') {
          return { id: 'nicolle_id', url: NICOLLE_AUDIO_URL, description: 'ESTÁS EN EL NEXO DIGITAL - Voz de Nicolle' };
        }
        return ONLY_SEPARATORS[Math.floor(Math.random() * ONLY_SEPARATORS.length)];
      } else {
        return ONLY_JINGLES[Math.floor(Math.random() * ONLY_JINGLES.length)];
      }
    }

    // 4. Música o Podcasts MP3 (80% Música / 20% Podcast)
    const isPodcast = Math.random() > 0.8;
    const source = isPodcast ? ONLY_PODCASTS : ONLY_MUSIC;
    const track = source[Math.floor(Math.random() * source.length)];

    // Evitar repetir la misma canción inmediatamente
    if (track.url === currentTrack?.url) return source[(source.indexOf(track) + 1) % source.length];
    return track;
  };

  const handleNext = () => {
    const next = getNextRadioTrack();
    setTrackCounter(prev => prev + 1);
    setCurrentTrack(next);
    nextVideo();
  };

  const nextVideo = () => {
    setVideoQueue(prev => {
      const [first, ...rest] = prev;
      return [...rest, first];
    });
  };

  useEffect(() => {
    const first = getNextRadioTrack();
    setCurrentTrack(first);
    setIsLoading(false);
  }, []);

  useEffect(() => {
    if (audioRef.current && currentTrack) {
      audioRef.current.load();
      if (isPlaying) {
        const playPromise = audioRef.current.play();
        if (playPromise !== undefined) {
          playPromise.catch(error => {
            console.error("Playback error:", error);
            setIsPlaying(false);
          });
        }
      }
    }
  }, [currentTrack]);

  const togglePlay = () => {
    if (isLoading || !audioRef.current) return;
    if (isPlaying) {
      audioRef.current.pause();
      setIsPlaying(false);
    } else {
      audioRef.current.play()
        .then(() => setIsPlaying(true))
        .catch(() => setIsPlaying(false));
    }
  };

  useImperativeHandle(ref, () => ({
    playRadio: () => { if (!isPlaying) togglePlay(); },
    pauseRadio: () => { if (isPlaying) togglePlay(); },
    getIsPlayingState: () => isPlaying
  }));

  // Listener para eventos globales de pausa
  useEffect(() => {
    const handleGlobalPause = () => {
      if (isPlaying && audioRef.current) {
        audioRef.current.pause();
        setIsPlaying(false);
      }
    };
    window.addEventListener('pauseRadio', handleGlobalPause);
    return () => window.removeEventListener('pauseRadio', handleGlobalPause);
  }, [isPlaying]);

  const displayTitle = currentTrack?.description || "Sintonizando El Nexo Digital...";
  const displayArtist = isLoading ? "Cargando..." : "RADIO EN VIVO";

  return (
    <header className="text-center relative select-none">
      <div className="gift-ribbon-wrapper">
        <div className="gift-ribbon">¡REGALOS EN BIBLIOTECA!</div>
      </div>

      <ListenerCounter />

      <div className="py-6 border-b-4 border-double border-stone-800 dark:border-stone-400">
        <img src="https://res.cloudinary.com/ddmj6zevz/image/upload/f_auto,q_auto:good/v1756714882/logo_el_nexo_digital_assa82.png" alt="Logo" className="mx-auto h-20 mb-2" />
        <h1 className="text-5xl md:text-7xl newspaper-title">El Nexo Digital</h1>
        <p className="text-[#dc2626] dark:text-[#ef4444] mt-2 text-sm uppercase tracking-[0.2em] font-black italic">Aplicación en desarrollo</p>
        <div className="flex justify-center items-center gap-4 mt-4">
          <p className="text-xs font-bold opacity-70 uppercase">{new Date().toLocaleDateString('es-ES', { weekday: 'long', day: 'numeric', month: 'long' })}</p>
          <button onClick={props.onToggleDarkMode} className="theme-switcher">{props.isDarkMode ? '🌞' : '🌙'}</button>
        </div>
      </div>

      <div className="my-4 overflow-hidden border-b-4 border-double border-stone-800 dark:border-stone-400 relative bg-black aspect-[1080/337] shadow-inner">
        <video 
          ref={videoRef}
          key={videoQueue[0]}
          src={videoQueue[0]} 
          autoPlay 
          muted 
          playsInline 
          onEnded={nextVideo}
          className="w-full h-full object-cover transition-opacity duration-1000 opacity-60"
        />

        <div className="absolute inset-0 flex items-center justify-between px-4 md:px-12 bg-gradient-to-r from-black/80 via-transparent to-black/80">
          <button 
            onClick={togglePlay}
            disabled={isLoading}
            className="group flex flex-col items-center justify-center gap-1 w-24 h-24 md:w-32 md:h-32 rounded-full bg-black/40 backdrop-blur-xl border-4 border-white/30 text-white hover:bg-red-700/80 hover:border-red-500 transition-all shadow-2xl disabled:opacity-50 hover:scale-110 active:scale-95 z-10"
          >
            {isPlaying ? (
              <>
                <svg className="w-10 h-10 md:w-14 md:h-14" fill="currentColor" viewBox="0 0 20 20">
                  <path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zM7 8a1 1 0 012 0v4a1 1 0 11-2 0V8zm4 0a1 1 0 012 0v4a1 1 0 11-2 0V8z" clipRule="evenodd" />
                </svg>
                <span className="text-[10px] md:text-xs font-black tracking-[0.2em] uppercase">PAUSA</span>
              </>
            ) : (
              <>
                <svg className="w-12 h-12 md:w-16 md:h-16 ml-1" fill="currentColor" viewBox="0 0 20 20">
                  <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168A1 1 0 008 8v4a1 1 0 001.555.832l3-2a1 1 0 000-1.664l-3-2z" clipRule="evenodd" />
                </svg>
                <span className="text-[10px] md:text-xs font-black tracking-[0.2em] uppercase ml-1">PLAY</span>
              </>
            )}
          </button>

          <div className="flex-1 text-center px-4 overflow-hidden text-white pointer-events-none">
            <h3 className="font-bold text-lg md:text-3xl truncate uppercase tracking-tighter drop-shadow-[0_2px_4px_rgba(0,0,0,1)]">{displayArtist}</h3>
            <div className="marquee-container mt-2">
              <div className="marquee-content font-typewriter italic text-2xl md:text-5xl py-2 drop-shadow-[0_4px_6px_rgba(0,0,0,1)]">
                {displayTitle} <span className="mx-16 opacity-50">•</span> {displayTitle}
              </div>
            </div>
          </div>

          <button 
            onClick={handleNext}
            className="px-4 py-2 text-[10px] md:text-sm border-2 border-white/50 text-white rounded-full hover:bg-white hover:text-black transition-all font-black uppercase backdrop-blur-md shadow-lg z-10 tracking-widest"
          >
            SALTAR
          </button>
        </div>
      </div>

      <audio 
        ref={audioRef} 
        src={currentTrack?.url} 
        onEnded={handleNext} 
        onError={handleNext} 
        preload="auto"
      />

      <div className="py-8 flex flex-wrap justify-center items-center gap-12 md:gap-20">
        {props.showPodcastButton && <FloatingPodcastButton onClick={props.onPodcastButtonClick} />}
        <button 
          onClick={props.onLibraryButtonClick} 
          className="group relative w-32 h-32 md:w-44 md:h-44 rounded-full shadow-2xl transition-all hover:scale-110 active:scale-95 bg-white dark:bg-stone-800 border-4 border-stone-800 dark:border-stone-400 overflow-hidden flex flex-col items-center justify-center"
        >
          <div className="absolute inset-0 flex items-center justify-center p-2">
            <img src="https://res.cloudinary.com/ddmj6zevz/image/upload/v1762221635/Gemini_Generated_Image_ooj0fjooj0fjooj0-removebg-preview_o1y7yh.png" alt="Biblioteca" className="w-full h-full object-contain group-hover:scale-110 transition-transform" />
          </div>
          <div className="absolute bottom-2 left-0 right-0 text-center">
            <span className="text-[10px] md:text-xs font-black uppercase tracking-widest bg-stone-900 text-white px-2 py-0.5 rounded">Biblioteca</span>
          </div>
        </button>
      </div>
    </header>
  );
});

