              disabled={isLoading}
              className="group/btn flex flex-col items-center justify-center gap-1 w-20 h-20 md:w-28 md:h-28 rounded-full bg-black/30 backdrop-blur-md border-2 border-white/40 text-white hover:bg-red-700/80 hover:border-red-400 transition-all shadow-xl disabled:opacity-50 hover:scale-110 active:scale-95 z-10"
