          }}
        >
          <video 
            ref={videoRef}
            key={videoQueue[0]}
            src={videoQueue[0]} 
            autoPlay 
            muted 
            playsInline 
            onEnded={nextVideo}
            className="w-full h-full object-cover opacity-80"
          />

          {/* Capa de interferencia / scanlines */}
          <div className="absolute inset-0 pointer-events-none opacity-20 bg-[linear-gradient(rgba(18,16,16,0)_50%,rgba(0,0,0,0.25)_50%),linear-gradient(90deg,rgba(255,0,0,0.06),rgba(0,255,0,0.02),rgba(0,0,255,0.06))] bg-[length:100%_2px,3px_100%]"></div>

          {/* Marquesina dentro del monitor */}
          <div className="absolute bottom-0 left-0 w-full bg-black/40 backdrop-blur-md border-t border-white/10">
             <div className="marquee-container">
