        <img src="https://res.cloudinary.com/ddmj6zevz/image/upload/f_auto,q_auto:good/v1756714882/logo_el_nexo_digital_assa82.png" alt="Logo" className="mx-auto h-20 mb-2" />
        <h1 className="text-5xl md:text-7xl newspaper-title">El Nexo Digital</h1>
        <p className="text-[#dc2626] dark:text-[#ef4444] mt-2 text-sm uppercase tracking-[0.2em] font-black italic">Aplicación en desarrollo</p>
        <div className="flex justify-center items-center gap-4 mt-4">
          <p className="text-xs font-bold opacity-70 uppercase">{new Date().toLocaleDateString('es-ES', { weekday: 'long', day: 'numeric', month: 'long' })}</p>
          <button onClick={props.onToggleDarkMode} className="theme-switcher text-2xl" aria-label="Cambiar tema">{props.isDarkMode ? '🌞' : '🌙'}</button>
        </div>
      </div>

      {/* Reproductor de Video Integrado */}
      <div className="my-6 max-w-4xl mx-auto px-4">
        <div className="bg-white dark:bg-stone-800 p-2 rounded-3xl shadow-2xl border-2 border-stone-200 dark:border-stone-700">
          <div className="relative bg-black rounded-2xl overflow-hidden aspect-video">
            <video 
              ref={videoRef}
              key={videoQueue[0]}
              src={videoQueue[0]} 
              autoPlay 
              muted 
              playsInline 
              onEnded={nextVideo}
              className="w-full h-full object-cover"
            />
            {/* Overlay de Carga */}
            {isLoading && (
              <div className="absolute inset-0 flex items-center justify-center bg-black">
                <div className="w-10 h-10 border-4 border-white/20 border-t-white rounded-full animate-spin"></div>
              </div>
            )}
          </div>

          {/* Marquesina e Información */}
          <div className="py-4 px-2">
            <div className="marquee-container mb-4">
              <div className="marquee-content font-typewriter italic text-sm md:text-xl text-stone-800 dark:text-stone-100">
                {displayTitle} <span className="mx-8 opacity-50">•</span> {displayTitle}
              </div>
            </div>

            {/* Controles de Reproducción */}
            <div className="flex items-center justify-center gap-8">
              <button 
                onClick={togglePlay}
                disabled={isLoading}
                className="w-16 h-16 rounded-full bg-stone-900 dark:bg-stone-100 text-white dark:text-stone-900 flex items-center justify-center transition-all transform hover:scale-110 active:scale-95 shadow-lg disabled:opacity-50"
                title={isPlaying ? "Pausar" : "Reproducir"}
              >
                {isPlaying ? (
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8" fill="currentColor" viewBox="0 0 24 24"><path d="M6 19h4V5H6v14zm8-14v14h4V5h-4z"/></svg>
                ) : (
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8 ml-1" fill="currentColor" viewBox="0 0 24 24"><path d="M8 5v14l11-7z"/></svg>
                )}
              </button>

              <button 
                onClick={handleNext}
                disabled={isLoading}
                className="w-12 h-12 rounded-full border-2 border-stone-300 dark:border-stone-600 flex items-center justify-center text-stone-600 dark:text-stone-400 hover:bg-stone-100 dark:hover:bg-stone-700 transition-all transform hover:scale-110 active:scale-95"
                title="Siguiente pista"
              >
                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="currentColor" viewBox="0 0 24 24"><path d="M6 18l8.5-6L6 6v12zM16 6v12h2V6h-2z"/></svg>
              </button>
            </div>
          </div>
        </div>
      </div>

      <audio ref={audioRef} src={currentTrack?.url} onEnded={handleNext} onError={handleNext} preload="auto" />

      {/* Botones de Navegación Principal */}
      <div className="py-8 flex flex-wrap justify-center items-center gap-12 md:gap-20">
        {props.showPodcastButton && <FloatingPodcastButton onClick={props.onPodcastButtonClick} />}
        <button 
          onClick={props.onLibraryButtonClick} 
          className="group relative w-32 h-32 md:w-44 md:h-44 rounded-full shadow-2xl transition-all hover:scale-110 active:scale-95 bg-white dark:bg-stone-800 border-4 border-stone-800 dark:border-stone-400 overflow-hidden flex flex-col items-center justify-center"
        >
          <div className="absolute inset-0 flex items-center justify-center p-2">
            <img src="https://res.cloudinary.com/ddmj6zevz/image/upload/v1762221635/Gemini_Generated_Image_ooj0fjooj0fjooj0-removebg-preview_o1y7yh.png" alt="Biblioteca" className="w-full h-full object-contain group-hover:scale-110 transition-transform" />
          </div>
          <div className="absolute bottom-2 left-0 right-0 text-center">
            <span className="text-[10px] md:text-xs font-black uppercase tracking-widest bg-stone-900 text-white px-2 py-0.5 rounded">Biblioteca</span>
          </div>
        </button>
      </div>
    </header>
  );
});

export default Header;

