          El Nexo Digital
        </h1>
        <div className="flex items-center gap-6 mt-6 opacity-60">
           <div className="h-[1px] w-12 bg-current"></div>
           <p className="text-[11px] uppercase tracking-[0.6em] font-bold">
            {new Date().toLocaleDateString('es-ES', { weekday: 'long', day: 'numeric', month: 'long' })}
           </p>
           <div className="h-[1px] w-12 bg-current"></div>
        </div>
      </div>

      {/* Reproductor Proporción 16:9 */}
      <div className="max-w-4xl mx-auto mb-16 px-4">
        <div className="player-container border border-black/10 dark:border-white/10 group">
          <video 
            ref={videoRef}
            key={videoQueue[0]}
            src={videoQueue[0]} 
            autoPlay 
            muted 
            playsInline 
            onEnded={nextVideo}
            className="w-full h-full object-cover"
          />

          {/* Botón Play centralizado e imaginativo */}
          <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
            <button 
              onClick={(e) => { e.stopPropagation(); togglePlay(); }}
              className={`pointer-events-auto w-24 h-24 rounded-full flex items-center justify-center backdrop-blur-md border border-white/30 transition-all duration-700 ${isPlaying ? 'opacity-0 scale-50' : 'opacity-100 scale-100 hover:bg-white/10'}`}
            >
               <svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10 text-white ml-2" fill="currentColor" viewBox="0 0 24 24"><path d="M8 5v14l11-7z"/></svg>
            </button>
          </div>

          {/* Marquesina News-Ticker */}
          <div className="absolute bottom-0 w-full news-ticker overflow-hidden">
             <div className="news-ticker-content flex items-center">
                <span className="mx-4 text-xs font-black uppercase tracking-widest text-red-500">EN VIVO</span>
                <p className="text-sm font-light uppercase tracking-[0.2em]">
                  {displayTitle} • {displayTitle} • {displayTitle}
                </p>
             </div>
          </div>
        </div>

        {/* Controles de Navegación del Player */}
        <div className="flex justify-center items-center gap-12 mt-8">
            <button onClick={togglePlay} className="hover:scale-110 active:scale-95 opacity-80 hover:opacity-100">
                {isPlaying ? (
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M10 9v6m4-6v6" />
                  </svg>
                ) : (
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M14.752 11.168l-3.197-2.132A1 1 0 0010 9.87v4.263a1 1 0 001.555.832l3.197-2.132a1 1 0 000-1.664z" />
                  </svg>
                )}
            </button>
            <button onClick={handleNext} className="hover:scale-110 active:scale-95 opacity-80 hover:opacity-100">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M13 5l7 7-7 7M5 5l7 7-7 7" />
                </svg>
            </button>
            <button onClick={props.onToggleDarkMode} className="text-xl opacity-60 hover:opacity-100 transition-opacity">
               {props.isDarkMode ? '🌞' : '🌙'}
            </button>
        </div>
      </div>

      <audio ref={audioRef} src={currentTrack?.url} onEnded={handleNext} onError={handleNext} preload="auto" />

      {/* Navegación Principal */}
      <div className="flex justify-center items-center gap-20">
        {props.showPodcastButton && <FloatingPodcastButton onClick={props.onPodcastButtonClick} />}
        <button 
          onClick={props.onLibraryButtonClick} 
          className="group flex flex-col items-center gap-4"
        >
          <div className="w-24 h-24 rounded-2xl bg-white dark:bg-stone-800 border border-black/5 dark:border-white/5 shadow-lg group-hover:shadow-2xl group-hover:scale-110 transition-all p-4">
            <img 
              src="https://res.cloudinary.com/ddmj6zevz/image/upload/v1762221635/Gemini_Generated_Image_ooj0fjooj0fjooj0-removebg-preview_o1y7yh.png" 
              alt="Biblioteca" 
              className="w-full h-full object-contain dark:invert" 
            />
          </div>
          <span className="text-[10px] uppercase tracking-[0.4em] font-black">Biblioteca</span>
        </button>
      </div>
    </header>
  );
});

export default Header;

