                )}
            </button>
            <button onClick={handleNext} className="hover:scale-125 active:scale-90 opacity-40 hover:opacity-100 transition-all">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M13 5l7 7-7 7M5 5l7 7-7 7" />
                </svg>
            </button>
            <button onClick={props.onToggleDarkMode} className="text-lg opacity-30 hover:opacity-100 transition-all">
               {props.isDarkMode ? '○' : '●'}
            </button>
        </div>
      </div>

      <audio ref={audioRef} src={currentTrack?.url} onEnded={handleNext} onError={handleNext} preload="auto" />

      {/* Navegación de Secciones */}
      <div className="flex justify-center items-center gap-24 mt-4">
        {props.showPodcastButton && <FloatingPodcastButton onClick={props.onPodcastButtonClick} />}
        <button 
          onClick={props.onLibraryButtonClick} 
          className="group flex flex-col items-center gap-3"
        >
          <div className="w-20 h-20 rounded-3xl bg-white dark:bg-stone-900 border border-black/5 dark:border-white/5 shadow-md group-hover:shadow-xl group-hover:scale-105 transition-all p-5">
            <img 
              src="https://res.cloudinary.com/ddmj6zevz/image/upload/v1762221635/Gemini_Generated_Image_ooj0fjooj0fjooj0-removebg-preview_o1y7yh.png" 
              alt="Biblioteca" 
              className="w-full h-full object-contain grayscale opacity-60 group-hover:grayscale-0 group-hover:opacity-100 transition-all duration-700 dark:invert" 
            />
          </div>
          <span className="text-[9px] uppercase tracking-[0.5em] font-bold opacity-40 group-hover:opacity-100">Biblioteca</span>
        </button>
      </div>
    </header>
  );
});

export default Header;

@import url('https://fonts.googleapis.com/css2?family=Inter:wght@300;400;700;900&family=Playfair+Display:ital,wght@0,700;1,400&display=swap');

@font-face {
  font-family: 'Britani';
  src: url('https://res.cloudinary.com/ddmj6zevz/raw/upload/v1756916641/brittany_ifg3wl.ttf') format('truetype');
  font-display: swap;
}

:root {
  --bg-light: #fdfaf4;
  --bg-dark: #0a0a0b;
}

* {
  transition: background-color 0.6s ease, color 0.6s ease, border-color 0.6s ease, transform 0.3s ease;
}

body {
  font-family: 'Inter', sans-serif;
  background-color: var(--bg-light);
  color: #1a1a1a;
  margin: 0;
  overflow-x: hidden;
}

body.dark {
  background-color: var(--bg-dark);
  color: #ffffff;
}

/* Fondo con Profundidad: Blobs de luz muy suaves */
.bg-glow {
  position: fixed;
  width: 40vw;
  height: 40vw;
  border-radius: 50%;
  filter: blur(120px);
  z-index: -1;
  opacity: 0.08;
  pointer-events: none;
  animation: float-glow 20s infinite alternate ease-in-out;
}

@keyframes float-glow {
  0% { transform: translate(-5%, -5%) scale(1); }
  100% { transform: translate(15%, 10%) scale(1.1); }
}

.newspaper-title {
  font-family: 'Britani', cursive;
  font-weight: normal;
  letter-spacing: -0.01em;
}

/* Reproductor Proporción 16:9 (El de ayer) */
.player-container {
  aspect-ratio: 16 / 9;
  width: 100%;
  max-width: 820px;
  margin: 0 auto;
  position: relative;
  background: #000;
  border-radius: 4px; /* Bordes más rectos para mayor seriedad */
  overflow: hidden;
  box-shadow: 0 40px 100px -20px rgba(0, 0, 0, 0.4);
}

/* Marquesina de Texto Puro */
.news-ticker {
  background: rgba(0, 0, 0, 0.9);
  backdrop-filter: blur(8px);
  color: #fff;
  padding: 10px 0;
  position: absolute;
  bottom: 0;
  width: 100%;
  z-index: 20;
  border-top: 1px solid rgba(255, 255, 255, 0.05);
}

.ticker-content {
  display: flex;
  white-space: nowrap;
  animation: ticker-animation 35s linear infinite;
}

@keyframes ticker-animation {
  0% { transform: translateX(100%); }
  100% { transform: translateX(-150%); }
}

/* Fix del Contador En Línea */
.listener-counter-wrapper {
  position: absolute;
  top: 1.5rem;
  right: 1.5rem;
  display: flex;
  align-items: center;
  gap: 8px;
  z-index: 50;
  padding: 6px 12px;
  border-radius: 4px;
  background: rgba(0, 0, 0, 0.05);
  border: 1px solid rgba(0, 0, 0, 0.05);
}

body.dark .listener-counter-wrapper {
  background: rgba(255, 255, 255, 0.05);
  border: 1px solid rgba(255, 255, 255, 0.1);
}

.status-dot {
  width: 6px;
  height: 6px;
  background: #22c55e;
  border-radius: 50%;
  box-shadow: 0 0 8px #22c55e;
}

/* Animaciones */
@keyframes fade-up {
  from { opacity: 0; transform: translateY(20px); }
  to { opacity: 1; transform: translateY(0); }
}

.animate-fade-up {
  animation: fade-up 1s ease-out forwards;
}

import React, { useState, useRef, useEffect, forwardRef, useImperativeHandle } from 'react';
import type { MusicTrack, HeaderControls } from '../types.ts';
import FloatingPodcastButton from './FloatingPodcastButton.tsx';
import ListenerCounter from './ListenerCounter.tsx';

import { ONLY_MUSIC, ONLY_PODCASTS, ONLY_SEPARATORS } from '../data/music.ts';
import { GREETING_AUDIOS } from '../greetings.ts';
import { TIME_JINGLES } from '../data/timeJingles.ts';
import { NEWS_BROADCASTS } from '../data/broadcasts.ts';

const VIDEO_URLS: string[] = [
  'https://res.cloudinary.com/dnauavz56/video/upload/v1764980525/atardecer_en_puerto_ikddmm.mp4',
  'https://res.cloudinary.com/ddmj6zevz/video/upload/v1757874034/tu_compa%C3%B1%C3%ADa_247_srq9ah.mp4',
  'https://res.cloudinary.com/dnauavz56/video/upload/v1764950849/postales2_mdcweq.mp4',
  'https://res.cloudinary.com/ddmj6zevz/video/upload/w_1280,q_auto:good/v1755907719/animaci%C3%B3n_APP_pvxjop.mp4'
];

const NICOLLE_AUDIO_URL = 'https://res.cloudinary.com/dgvkbrgre/video/upload/q_auto:good/v1756197263/exclusivo_del_nexo_nicolle_gxsl68.mp3';

interface HeaderProps {
  isPodcastModalOpen: boolean;
  onPodcastButtonClick: () => void;
  showPodcastButton: boolean;
  onLibraryButtonClick: () => void;
  isDarkMode: boolean;
  onToggleDarkMode: () => void;
}

const Header = forwardRef<HeaderControls, HeaderProps>((props, ref) => {
  const [isPlaying, setIsPlaying] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [currentTrack, setCurrentTrack] = useState<MusicTrack | null>(null);
  const [videoQueue, setVideoQueue] = useState<string[]>(() => [...VIDEO_URLS].sort(() => Math.random() - 0.5));
  const [trackCounter, setTrackCounter] = useState(0);

  const audioRef = useRef<HTMLAudioElement>(null);
  const videoRef = useRef<HTMLVideoElement>(null);

  const getNextRadioTrack = (): MusicTrack => {
    const hour = new Date().getHours();
    if (NEWS_BROADCASTS[hour] && currentTrack?.id !== NEWS_BROADCASTS[hour].id) return NEWS_BROADCASTS[hour];

    if (trackCounter > 0 && trackCounter % 5 === 0) {
      const timeOfDay = hour < 12 ? 'morning' : hour < 19 ? 'afternoon' : 'night';
      const pool = Math.random() > 0.5 ? GREETING_AUDIOS[timeOfDay] : TIME_JINGLES[timeOfDay];
      return { id: `greet_${Date.now()}`, url: pool[Math.floor(Math.random() * pool.length)], description: 'Sintonía El Nexo Digital' };
    }

    if (trackCounter > 0 && trackCounter % 2 === 0) {
      if (Math.random() < 0.5 && currentTrack?.id !== 'nicolle_id') {
        return { id: 'nicolle_id', url: NICOLLE_AUDIO_URL, description: 'ESTÁS EN EL NEXO DIGITAL - Voz de Nicolle' };
      }
      return ONLY_SEPARATORS[Math.floor(Math.random() * ONLY_SEPARATORS.length)];
    }

    const isPodcast = Math.random() > 0.8;
    const source = isPodcast ? ONLY_PODCASTS : ONLY_MUSIC;
    return source[Math.floor(Math.random() * source.length)];
  };

  const handleNext = () => {
    const next = getNextRadioTrack();
    setTrackCounter(prev => prev + 1);
    setCurrentTrack(next);
    nextVideo();
  };

  const nextVideo = () => {
    setVideoQueue(prev => {
      const [first, ...rest] = prev;
      return [...rest, first];
    });
  };

  useEffect(() => {
    const first = getNextRadioTrack();
    setCurrentTrack(first);
    setIsLoading(false);
  }, []);

  useEffect(() => {
    if (audioRef.current && currentTrack) {
      audioRef.current.load();
      if (isPlaying) {
        audioRef.current.play().catch(() => setIsPlaying(false));
      }
    }
  }, [currentTrack]);

  const togglePlay = () => {
    if (isLoading || !audioRef.current) return;
    if (isPlaying) {
      audioRef.current.pause();
      setIsPlaying(false);
    } else {
      audioRef.current.play().then(() => setIsPlaying(true)).catch(() => setIsPlaying(false));
    }
  };

  useImperativeHandle(ref, () => ({
    playRadio: () => { if (!isPlaying) togglePlay(); },
    pauseRadio: () => { if (isPlaying) togglePlay(); },
    getIsPlayingState: () => isPlaying
  }));

  const displayTitle = currentTrack?.description || "Inspiración para tu día...";

  return (
    <header className="relative pt-24 pb-12 px-6">
      <div className="bg-glow bg-blue-400 left-0 top-0 opacity-10"></div>
      <div className="bg-glow bg-red-400 right-0 bottom-0 opacity-5"></div>

      <ListenerCounter />

      {/* Título de Marca: Tamaño reducido y color dinámico */}
      <div className="max-w-screen-xl mx-auto flex flex-col items-center mb-20 animate-fade-up">
        <h1 className="text-4xl md:text-6xl newspaper-title text-black dark:text-white transition-colors duration-700 select-none tracking-tight">
          El Nexo Digital
        </h1>
        <div className="flex items-center gap-6 mt-6 opacity-30">
           <div className="h-[1px] w-10 bg-current"></div>
           <p className="text-[10px] uppercase tracking-[0.6em] font-bold">
            {new Date().toLocaleDateString('es-ES', { weekday: 'long', day: 'numeric', month: 'long' })}
           </p>
           <div className="h-[1px] w-10 bg-current"></div>
        </div>
      </div>

      {/* Reproductor Cinemático 16:9 */}
      <div className="max-w-4xl mx-auto mb-16 px-4 animate-fade-up" style={{ animationDelay: '0.2s' }}>
        <div className="player-container border border-black/5 dark:border-white/5">
          <video 
            ref={videoRef}
            key={videoQueue[0]}
            src={videoQueue[0]} 
            autoPlay 
            muted 
            playsInline 
            onEnded={nextVideo}
            className="w-full h-full object-cover"
          />

          {/* Overlay de Control Central */}
          <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
            <button 
              onClick={(e) => { e.stopPropagation(); togglePlay(); }}
              className={`pointer-events-auto w-20 h-20 rounded-full flex items-center justify-center backdrop-blur-md border border-white/20 transition-all duration-1000 ${isPlaying ? 'opacity-0 scale-75' : 'opacity-100 scale-100 bg-white/5 hover:bg-white/10'}`}
            >
               <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8 text-white ml-1" fill="currentColor" viewBox="0 0 24 24"><path d="M8 5v14l11-7z"/></svg>
            </button>
          </div>

          {/* Marquesina depurada (Solo Texto) */}
          <div className="news-ticker overflow-hidden">
             <div className="ticker-content">
                <span className="mx-8 text-[10px] font-black uppercase tracking-[0.4em] text-red-500">RADIODIFUSIÓN EN VIVO</span>
                <p className="text-xs font-light uppercase tracking-[0.3em]">
                  {displayTitle} &nbsp;&nbsp; • &nbsp;&nbsp; {displayTitle} &nbsp;&nbsp; • &nbsp;&nbsp; {displayTitle}
                </p>
             </div>
          </div>
        </div>

        {/* Controles de Navegación Minimalistas */}
        <div className="flex justify-center items-center gap-16 mt-12">
            <button onClick={togglePlay} className="hover:scale-125 active:scale-90 opacity-40 hover:opacity-100 transition-all">
                {isPlaying ? (
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-7 w-7" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M10 9v6m4-6v6" />
                  </svg>
                ) : (
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-7 w-7" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M14.752 11.168l-3.197-2.132A1 1 0 0010 9.87v4.263a1 1 0 001.555.832l3.197-2.132a1 1 0 000-1.664z" />
                  </svg>
                )}
            </button>
            <button onClick={handleNext} className="hover:scale-125 active:scale-90 opacity-20 hover:opacity-100 transition-all">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M13 5l7 7-7 7M5 5l7 7-7 7" />
                </svg>
            </button>
            <button onClick={props.onToggleDarkMode} className="text-sm font-bold opacity-20 hover:opacity-100 transition-all">
               {props.isDarkMode ? 'MODO LUZ' : 'MODO NOCHE'}
            </button>
        </div>
      </div>

      <audio ref={audioRef} src={currentTrack?.url} onEnded={handleNext} onError={handleNext} preload="auto" />

      {/* Navegación Principal */}
      <div className="flex justify-center items-center gap-24 mt-4 animate-fade-up" style={{ animationDelay: '0.4s' }}>
        {props.showPodcastButton && <FloatingPodcastButton onClick={props.onPodcastButtonClick} />}
        <button 
          onClick={props.onLibraryButtonClick} 
          className="group flex flex-col items-center gap-4"
        >
          <div className="w-20 h-20 rounded-xl bg-white dark:bg-stone-900 border border-black/5 dark:border-white/5 shadow-lg group-hover:scale-110 transition-all p-5">
            <img 
              src="https://res.cloudinary.com/ddmj6zevz/image/upload/v1762221635/Gemini_Generated_Image_ooj0fjooj0fjooj0-removebg-preview_o1y7yh.png" 
              alt="Biblioteca" 
              className="w-full h-full object-contain grayscale opacity-60 group-hover:grayscale-0 group-hover:opacity-100 transition-all duration-700 dark:invert" 
            />
          </div>
          <span className="text-[9px] uppercase tracking-[0.5em] font-black opacity-30 group-hover:opacity-100">Biblioteca</span>
        </button>
      </div>
    </header>
  );
});

export default Header;
